import { masterDataService } from "./MasterDataService";

export async function fetchMasterDataConf() {
    let response = await masterDataService.fetchMasterDataConf();
    return response;
}

export async function getUserType() {
    let response = await masterDataService.getUserType();
    return response;
}

export async function saveMasterDataConf(masterData) {
    let response = await masterDataService.saveMasterDataConf(masterData);
    return response;
}
